const CARDS = [
  {id:1,emoji:'📖',ar:{title:'القرآن دليل حياة',desc:'القرآن ليس كتاب تلاوة فحسب بل هو منهج حياة كامل. من قرأه بتدبر وجد فيه حلاً لكل مشكلة.',approach:'اجعل القرآن مرجعك الأول في كل قرار',wisdom:'التدبر هو مفتاح الاستفادة الحقيقية من القرآن',action:'اقرأ صفحة من القرآن اليوم بتدبر وتأمل'},en:{title:'The Quran Is a Life Guide',desc:'The Quran is not just a book for recitation but a complete way of life. Whoever reads it with reflection finds a solution to every problem.',approach:'Make the Quran your first reference in every decision',wisdom:'Reflection is the key to truly benefiting from the Quran',action:'Read a page of the Quran today with reflection and contemplation'},fr:{title:'Le Coran Est un Guide de Vie',desc:'Le Coran n\'est pas seulement un livre de récitation mais un mode de vie complet. Celui qui le lit avec réflexion y trouve une solution à chaque problème.',approach:'Faites du Coran votre première référence dans chaque décision',wisdom:'La réflexion est la clé pour vraiment bénéficier du Coran',action:'Lisez une page du Coran aujourd\'hui avec réflexion et contemplation'}},
  {id:2,emoji:'🧠',ar:{title:'القراءة بفهم لا بتلقين',desc:'كثيرون يقرأون القرآن دون فهم. الشيخ الغزالي يؤكد أن القراءة بلا فهم تفقد القرآن أثره في النفس.',approach:'اقرأ تفسيراً مبسطاً مع كل سورة تقرأها',wisdom:'الفهم يحول التلاوة من عادة إلى عبادة واعية',action:'اختر سورة قصيرة اليوم واقرأ تفسيرها'},en:{title:'Reading with Understanding, Not Rote',desc:'Many read the Quran without understanding. Sheikh al-Ghazali emphasizes that reading without comprehension strips the Quran of its impact on the soul.',approach:'Read a simple tafsir alongside every surah you read',wisdom:'Understanding transforms recitation from habit to conscious worship',action:'Choose a short surah today and read its tafsir'},fr:{title:'Lire avec Compréhension, Pas par Coeur',desc:'Beaucoup lisent le Coran sans comprendre. Sheikh al-Ghazali souligne que la lecture sans compréhension prive le Coran de son impact sur l\'âme.',approach:'Lisez un tafsir simple avec chaque sourate que vous lisez',wisdom:'La compréhension transforme la récitation d\'habitude en adoration consciente',action:'Choisissez une courte sourate aujourd\'hui et lisez son tafsir'}},
  {id:3,emoji:'🌍',ar:{title:'القرآن والحياة المعاصرة',desc:'القرآن صالح لكل زمان ومكان. مبادئه تعالج مشاكل العصر الحديث بنفس كفاءة معالجتها لمشاكل الماضي.',approach:'ابحث في القرآن عن إجابات لمشاكلك الحقيقية',wisdom:'القرآن لم يقتصر على عصر معين بل تجاوز كل العصور',action:'فكّر في مشكلة تواجهها وابحث في القرآن عن توجيه لها'},en:{title:'The Quran and Modern Life',desc:'The Quran is valid for all times and places. Its principles address modern problems as effectively as it addressed those of the past.',approach:'Search the Quran for answers to your real problems',wisdom:'The Quran was not limited to a specific era but transcended all eras',action:'Think of a problem you face and search the Quran for guidance'},fr:{title:'Le Coran et la Vie Moderne',desc:'Le Coran est valide pour tous les temps et lieux. Ses principes traitent les problèmes modernes aussi efficacement que ceux du passé.',approach:'Cherchez dans le Coran des réponses à vos vrais problèmes',wisdom:'Le Coran n\'était pas limité à une époque spécifique mais a transcendé toutes les époques',action:'Pensez à un problème que vous affrontez et cherchez dans le Coran une guidance'}},
  {id:4,emoji:'📚',ar:{title:'المنهج الموضوعي في القراءة',desc:'بدلاً من القراءة العشوائية، اتبع منهجاً موضوعياً: اختر موضوعاً وتتبع آيات القرآن المتعلقة به.',approach:'اجمع الآيات المتعلقة بموضوع واحد وادرسها معاً',wisdom:'المنهج الموضوعي يكشف عمق القرآن وترابط آياته',action:'اختر موضوعاً (مثل: الصبر) واجمع ٥ آيات عنه'},en:{title:'The Thematic Approach to Reading',desc:'Instead of random reading, follow a thematic approach: choose a topic and trace the Quranic verses related to it.',approach:'Gather verses related to one topic and study them together',wisdom:'The thematic approach reveals the depth and coherence of the Quran',action:'Choose a topic (e.g., patience) and gather 5 verses about it'},fr:{title:'L\'Approche Thématique de la Lecture',desc:'Au lieu d\'une lecture aléatoire, suivez une approche thématique : choisissez un sujet et retracez les versets coraniques liés.',approach:'Rassemblez les versets liés à un sujet et étudiez-les ensemble',wisdom:'L\'approche thématique révèle la profondeur et la cohérence du Coran',action:'Choisissez un sujet (ex : la patience) et rassemblez 5 versets à ce sujet'}},
  {id:5,emoji:'🔬',ar:{title:'القرآن والعلم',desc:'القرآن ليس كتاب علوم طبيعية لكنه لا يتعارض مع العلم الصحيح. الإشارات العلمية فيه تدل على عظمته.',approach:'لا تحوّل القرآن إلى كتاب فيزياء لكن تأمل إشاراته العلمية',wisdom:'الانبهار بالعلم لا يعني تأويل القرآن بالقوة ليوافق كل نظرية',action:'اقرأ عن إعجاز القرآن العلمي من مصادر موثوقة'},en:{title:'The Quran and Science',desc:'The Quran is not a natural science textbook but it does not contradict sound science. Its scientific allusions attest to its greatness.',approach:'Don\'t turn the Quran into a physics book, but reflect on its scientific allusions',wisdom:'Being impressed by science doesn\'t mean forcing Quranic interpretation to match every theory',action:'Read about the Quran\'s scientific miracles from reliable sources'},fr:{title:'Le Coran et la Science',desc:'Le Coran n\'est pas un manuel de sciences naturelles mais il ne contredit pas la science saine. Ses allusions scientifiques témoignent de sa grandeur.',approach:'Ne transformez pas le Coran en livre de physique, mais réfléchissez à ses allusions scientifiques',wisdom:'Être impressionné par la science ne signifie pas forcer l\'interprétation coranique',action:'Lisez sur les miracles scientifiques du Coran de sources fiables'}},
  {id:6,emoji:'💎',ar:{title:'الحفظ والفهم معاً',desc:'حفظ القرآن فضيلة عظيمة لكنه لا يكفي وحده. الجمع بين الحفظ والفهم هو الكمال.',approach:'احفظ بفهم وفهم بتطبيق',wisdom:'حافظ بلا فهم كمن يحمل كنزاً مغلقاً',action:'راجع اليوم ما تحفظه واقرأ تفسير آية واحدة منه'},en:{title:'Memorization and Understanding Together',desc:'Memorizing the Quran is a great virtue but not sufficient alone. Combining memorization with understanding is perfection.',approach:'Memorize with understanding and understand through application',wisdom:'A memorizer without understanding is like one carrying a locked treasure',action:'Review what you\'ve memorized today and read the tafsir of one verse from it'},fr:{title:'Mémorisation et Compréhension Ensemble',desc:'Mémoriser le Coran est une grande vertu mais insuffisant seul. Combiner mémorisation et compréhension est la perfection.',approach:'Mémorisez avec compréhension et comprenez par l\'application',wisdom:'Un mémorisateur sans compréhension est comme celui qui porte un trésor verrouillé',action:'Révisez ce que vous avez mémorisé aujourd\'hui et lisez le tafsir d\'un verset'}},
  {id:7,emoji:'🌱',ar:{title:'التدرج في الفهم',desc:'فهم القرآن يأتي بالتدرج. كلما زادت معرفتك وتجربتك في الحياة، اكتشفت معاني جديدة في نفس الآيات.',approach:'أعد قراءة سور مألوفة بنظرة جديدة كل فترة',wisdom:'القرآن لا تنقضي عجائبه — كل قراءة تكشف جديداً',action:'أعد قراءة سورة تعرفها جيداً بعيون جديدة اليوم'},en:{title:'Gradual Understanding',desc:'Understanding the Quran comes gradually. As your knowledge and life experience grow, you discover new meanings in the same verses.',approach:'Re-read familiar surahs with fresh eyes periodically',wisdom:'The wonders of the Quran never end — every reading reveals something new',action:'Re-read a surah you know well with fresh eyes today'},fr:{title:'Compréhension Graduelle',desc:'La compréhension du Coran vient graduellement. À mesure que votre connaissance et expérience croissent, vous découvrez de nouveaux sens.',approach:'Relisez des sourates familières avec un regard neuf périodiquement',wisdom:'Les merveilles du Coran ne s\'épuisent jamais — chaque lecture révèle du nouveau',action:'Relisez une sourate que vous connaissez bien avec un regard neuf aujourd\'hui'}},
  {id:8,emoji:'❌',ar:{title:'تجنب القراءة الحرفية الجامدة',desc:'القراءة الحرفية بلا فقه تؤدي إلى فهم خاطئ. القرآن يحتاج فهماً يراعي السياق واللغة والمقصد.',approach:'لا تتوقف عند ظاهر النص بل ابحث عن المقصد والحكمة',wisdom:'الحرفية الجامدة قد تحول القرآن من رحمة إلى حجة',action:'عندما تقرأ آية صعبة، ارجع إلى تفاسير العلماء المعتبرين'},en:{title:'Avoid Rigid Literalism',desc:'Literal reading without jurisprudence leads to misunderstanding. The Quran needs understanding that considers context, language, and purpose.',approach:'Don\'t stop at the apparent text but search for the purpose and wisdom',wisdom:'Rigid literalism can turn the Quran from mercy into an argument',action:'When you read a difficult verse, refer to respected scholars\' commentaries'},fr:{title:'Éviter le Littéralisme Rigide',desc:'La lecture littérale sans jurisprudence mène à l\'incompréhension. Le Coran nécessite une compréhension qui considère le contexte, la langue et l\'objectif.',approach:'Ne vous arrêtez pas au texte apparent mais cherchez l\'objectif et la sagesse',wisdom:'Le littéralisme rigide peut transformer le Coran de miséricorde en argument',action:'Quand vous lisez un verset difficile, consultez les commentaires de savants respectés'}},
  {id:9,emoji:'🤲',ar:{title:'القرآن والدعاء',desc:'القرآن مليء بالأدعية. تعلّم الدعاء من القرآن يجعل دعاءك أبلغ وأعمق.',approach:'احفظ أدعية القرآن وادعُ بها في صلاتك',wisdom:'دعاء القرآن يجمع بين البلاغة والحكمة والإيمان',action:'احفظ دعاءً قرآنياً جديداً اليوم وادعُ به'},en:{title:'The Quran and Supplication',desc:'The Quran is full of supplications. Learning to pray from the Quran makes your prayers more eloquent and profound.',approach:'Memorize Quranic duas and use them in your prayers',wisdom:'Quranic supplications combine eloquence, wisdom, and faith',action:'Memorize a new Quranic dua today and use it in prayer'},fr:{title:'Le Coran et l\'Invocation',desc:'Le Coran est plein d\'invocations. Apprendre à prier du Coran rend vos prières plus éloquentes et profondes.',approach:'Mémorisez les duas coraniques et utilisez-les dans vos prières',wisdom:'Les invocations coraniques combinent éloquence, sagesse et foi',action:'Mémorisez une nouvelle dua coranique aujourd\'hui et utilisez-la dans la prière'}},
  {id:10,emoji:'👨‍👩‍👧‍👦',ar:{title:'القرآن في البيت',desc:'اجعل القرآن حاضراً في بيتك: اقرأه جهراً، ناقش معانيه مع أسرتك، علّم أطفالك محبته.',approach:'خصص وقتاً عائلياً لقراءة القرآن ومناقشته',wisdom:'البيت الذي يُقرأ فيه القرآن تحفه السكينة',action:'اقرأ مع أسرتك سورة قصيرة الليلة وتحدثوا عن معانيها'},en:{title:'The Quran in the Home',desc:'Make the Quran present in your home: read it aloud, discuss its meanings with your family, teach your children to love it.',approach:'Set aside family time for Quran reading and discussion',wisdom:'The home where the Quran is read is surrounded by tranquility',action:'Read a short surah with your family tonight and discuss its meanings'},fr:{title:'Le Coran au Foyer',desc:'Rendez le Coran présent dans votre foyer : lisez-le à voix haute, discutez de ses sens avec votre famille, enseignez à vos enfants à l\'aimer.',approach:'Réservez du temps familial pour la lecture et la discussion du Coran',wisdom:'Le foyer où le Coran est lu est entouré de sérénité',action:'Lisez une courte sourate avec votre famille ce soir et discutez de ses sens'}},
  {id:11,emoji:'🎵',ar:{title:'جمال التلاوة',desc:'القرآن جمع بين المعنى والجمال الصوتي. التلاوة الحسنة تؤثر في القلب وتفتح أبواب التدبر.',approach:'تعلّم أحكام التجويد لتحسين تلاوتك',wisdom:'الصوت الحسن مع الفهم يضاعف أثر القرآن',action:'استمع اليوم إلى تلاوة جميلة لقارئ تحبه وتأمل'},en:{title:'The Beauty of Recitation',desc:'The Quran combines meaning with sonic beauty. Beautiful recitation touches hearts and opens doors to reflection.',approach:'Learn tajweed rules to improve your recitation',wisdom:'A beautiful voice with understanding multiplies the Quran\'s impact',action:'Listen today to a beautiful recitation by a reader you love and reflect'},fr:{title:'La Beauté de la Récitation',desc:'Le Coran combine le sens avec la beauté sonore. La belle récitation touche les coeurs et ouvre les portes de la réflexion.',approach:'Apprenez les règles du tajweed pour améliorer votre récitation',wisdom:'Une belle voix avec compréhension multiplie l\'impact du Coran',action:'Écoutez aujourd\'hui une belle récitation d\'un lecteur que vous aimez et réfléchissez'}},
  {id:12,emoji:'⚖️',ar:{title:'القرآن والعدل',desc:'القرآن يأمر بالعدل حتى مع المخالف. العدل في القرآن مطلق لا يخضع للهوى أو المصلحة.',approach:'طبّق العدل القرآني في تعاملاتك اليومية',wisdom:'العدل في القرآن ليس فقط مع من تحب بل حتى مع من تختلف معه',action:'كن عادلاً اليوم في حكمك على موقف أو شخص'},en:{title:'The Quran and Justice',desc:'The Quran commands justice even with opponents. Justice in the Quran is absolute, not subject to desire or interest.',approach:'Apply Quranic justice in your daily dealings',wisdom:'Justice in the Quran is not only with those you love but even with those you disagree with',action:'Be just today in your judgment of a situation or person'},fr:{title:'Le Coran et la Justice',desc:'Le Coran ordonne la justice même envers les opposants. La justice dans le Coran est absolue, non soumise au désir ou à l\'intérêt.',approach:'Appliquez la justice coranique dans vos transactions quotidiennes',wisdom:'La justice dans le Coran n\'est pas seulement envers ceux qu\'on aime mais même envers ceux avec qui on n\'est pas d\'accord',action:'Soyez juste aujourd\'hui dans votre jugement d\'une situation ou personne'}},
  {id:13,emoji:'💝',ar:{title:'القرآن شفاء للقلوب',desc:'القرآن شفاء روحي ونفسي. من قرأه بإيمان وجد فيه سكينة لا يجدها في أي مكان آخر.',approach:'عندما تشعر بالضيق، افتح القرآن واقرأ بتدبر',wisdom:'القرآن يعالج القلوب قبل الأجسام',action:'عندما تشعر بالحزن اليوم، اقرأ سورة الضحى أو الشرح'},en:{title:'The Quran Heals Hearts',desc:'The Quran is spiritual and psychological healing. Whoever reads it with faith finds tranquility found nowhere else.',approach:'When you feel distressed, open the Quran and read with reflection',wisdom:'The Quran heals hearts before bodies',action:'When you feel sad today, read Surah Ad-Duha or Ash-Sharh'},fr:{title:'Le Coran Guérit les Coeurs',desc:'Le Coran est une guérison spirituelle et psychologique. Celui qui le lit avec foi y trouve une sérénité introuvable ailleurs.',approach:'Quand vous vous sentez en détresse, ouvrez le Coran et lisez avec réflexion',wisdom:'Le Coran guérit les coeurs avant les corps',action:'Quand vous vous sentez triste aujourd\'hui, lisez Sourate Ad-Duha ou Ash-Sharh'}},
  {id:14,emoji:'🗺️',ar:{title:'خريطة القرآن',desc:'لكل سورة موضوع رئيسي ومحور. فهم خريطة القرآن يساعد في الربط بين السور وفهم البناء العام.',approach:'تعلّم الموضوع الرئيسي لكل سورة تقرأها',wisdom:'القرآن بناء متكامل لا مجموعة آيات عشوائية',action:'اقرأ عن الموضوع الرئيسي لسورة البقرة اليوم'},en:{title:'The Map of the Quran',desc:'Every surah has a main theme and axis. Understanding the Quran\'s map helps connect surahs and understand the overall structure.',approach:'Learn the main theme of every surah you read',wisdom:'The Quran is an integrated structure, not a random collection of verses',action:'Read about the main theme of Surah Al-Baqarah today'},fr:{title:'La Carte du Coran',desc:'Chaque sourate a un thème principal et un axe. Comprendre la carte du Coran aide à relier les sourates et comprendre la structure globale.',approach:'Apprenez le thème principal de chaque sourate que vous lisez',wisdom:'Le Coran est une structure intégrée, pas une collection aléatoire de versets',action:'Lisez sur le thème principal de Sourate Al-Baqarah aujourd\'hui'}},
  {id:15,emoji:'📝',ar:{title:'القرآن والتطبيق العملي',desc:'العلم بالقرآن بلا عمل كالشجرة بلا ثمر. كل آية تقرأها يجب أن تترجمها إلى سلوك عملي.',approach:'بعد كل قراءة، اكتب عملاً واحداً ستطبقه',wisdom:'القرآن نزل ليُعمل به لا ليُتلى فقط',action:'اختر آية قرأتها اليوم وحدد فعلاً واحداً تطبقه منها'},en:{title:'The Quran and Practical Application',desc:'Knowledge of the Quran without action is like a tree without fruit. Every verse you read should be translated into practical behavior.',approach:'After every reading, write one action you will apply',wisdom:'The Quran was revealed to be acted upon, not just recited',action:'Choose a verse you read today and identify one action to apply from it'},fr:{title:'Le Coran et l\'Application Pratique',desc:'La connaissance du Coran sans action est comme un arbre sans fruit. Chaque verset que vous lisez doit être traduit en comportement pratique.',approach:'Après chaque lecture, écrivez une action que vous appliquerez',wisdom:'Le Coran a été révélé pour être mis en pratique, pas seulement récité',action:'Choisissez un verset lu aujourd\'hui et identifiez une action à en appliquer'}},
  {id:16,emoji:'🌊',ar:{title:'القصص القرآني',desc:'قصص القرآن ليست للتسلية بل للاعتبار والتعلم. كل قصة تحمل دروساً خالدة.',approach:'استخرج الدرس من كل قصة قرآنية تقرأها',wisdom:'قصص الأنبياء في القرآن هي نماذج حية للتعامل مع الحياة',action:'اقرأ قصة نبي في القرآن واستخرج ٣ دروس عملية'},en:{title:'Quranic Stories',desc:'Quranic stories are not for entertainment but for lessons and learning. Every story carries timeless lessons.',approach:'Extract the lesson from every Quranic story you read',wisdom:'Stories of prophets in the Quran are living models for dealing with life',action:'Read a prophet\'s story in the Quran and extract 3 practical lessons'},fr:{title:'Les Récits Coraniques',desc:'Les récits coraniques ne sont pas pour le divertissement mais pour les leçons et l\'apprentissage. Chaque récit porte des leçons intemporelles.',approach:'Extrayez la leçon de chaque récit coranique que vous lisez',wisdom:'Les récits des prophètes dans le Coran sont des modèles vivants pour la vie',action:'Lisez l\'histoire d\'un prophète dans le Coran et extrayez 3 leçons pratiques'}},
  {id:17,emoji:'🌟',ar:{title:'إعجاز القرآن',desc:'القرآن معجز في لغته وبلاغته ومعانيه وتشريعاته. لا يستطيع البشر أن يأتوا بمثله.',approach:'تأمل في جوانب الإعجاز المختلفة: لغوي، علمي، تشريعي',wisdom:'الإعجاز يتجدد مع كل عصر ومع كل اكتشاف جديد',action:'تأمل في آية واحدة اليوم من جهة البلاغة والمعنى'},en:{title:'The Quran\'s Inimitability',desc:'The Quran is miraculous in its language, eloquence, meanings, and legislation. Humans cannot produce anything like it.',approach:'Reflect on different aspects of its inimitability: linguistic, scientific, legislative',wisdom:'The miracle is renewed with every era and every new discovery',action:'Reflect on one verse today from the perspective of eloquence and meaning'},fr:{title:'L\'Inimitabilité du Coran',desc:'Le Coran est miraculeux dans sa langue, son éloquence, ses sens et sa législation. Les humains ne peuvent produire rien de semblable.',approach:'Réfléchissez aux différents aspects de son inimitabilité : linguistique, scientifique, législatif',wisdom:'Le miracle se renouvelle avec chaque époque et chaque nouvelle découverte',action:'Réfléchissez à un verset aujourd\'hui du point de vue de l\'éloquence et du sens'}},
  {id:18,emoji:'🕊️',ar:{title:'القرآن والسلام الداخلي',desc:'القرآن يمنح قارئه سلاماً داخلياً لا مثيل له. ذكر الله وتلاوة كتابه تطمئن القلب وتزيل القلق.',approach:'اجعل القرآن رفيقك اليومي في الصباح والمساء',wisdom:'ألا بذكر الله تطمئن القلوب — والقرآن أعظم الذكر',action:'ابدأ يومك بقراءة ورد قرآني ولاحظ أثره على يومك'},en:{title:'The Quran and Inner Peace',desc:'The Quran grants its reader an unparalleled inner peace. Remembering God and reciting His Book calms the heart and removes anxiety.',approach:'Make the Quran your daily companion morning and evening',wisdom:'Truly, in the remembrance of God hearts find peace — the Quran is the greatest remembrance',action:'Start your day with a Quranic reading and notice its effect on your day'},fr:{title:'Le Coran et la Paix Intérieure',desc:'Le Coran accorde à son lecteur une paix intérieure sans pareil. Le rappel de Dieu et la récitation de Son Livre calment le coeur.',approach:'Faites du Coran votre compagnon quotidien matin et soir',wisdom:'C\'est dans le rappel de Dieu que les coeurs trouvent la paix — le Coran est le plus grand rappel',action:'Commencez votre journée avec une lecture coranique et observez son effet sur votre journée'}},
  {id:19,emoji:'🔄',ar:{title:'المراجعة المستمرة',desc:'القرآن يحتاج مراجعة مستمرة. من ترك المراجعة تفلّت منه القرآن كما يتفلت البعير من عقاله.',approach:'خصص وقتاً يومياً ثابتاً لمراجعة ما تحفظه',wisdom:'المداومة على القليل خير من الانقطاع عن الكثير',action:'راجع اليوم جزءاً مما تحفظه ولو صفحة واحدة'},en:{title:'Continuous Review',desc:'The Quran needs continuous review. Whoever abandons review will find the Quran slipping away like a camel escaping its tether.',approach:'Set a fixed daily time for reviewing what you\'ve memorized',wisdom:'Consistency with little is better than stopping after much',action:'Review a part of what you\'ve memorized today, even just one page'},fr:{title:'Révision Continue',desc:'Le Coran nécessite une révision continue. Celui qui abandonne la révision trouvera le Coran s\'échapper comme un chameau de son attache.',approach:'Réservez un temps quotidien fixe pour réviser ce que vous avez mémorisé',wisdom:'La constance avec peu est meilleure que l\'abandon après beaucoup',action:'Révisez une partie de ce que vous avez mémorisé aujourd\'hui, même une seule page'}},
  {id:20,emoji:'💡',ar:{title:'القرآن نور',desc:'القرآن نور يضيء الطريق في ظلمات الحياة. من استنار بالقرآن لن يضل أبداً.',approach:'اجعل القرآن بوصلتك في كل مفترق طرق',wisdom:'القرآن هو حبل الله المتين — من تمسك به نجا',action:'تأمل اليوم كيف يمكن للقرآن أن ينير قراراتك وحياتك'},en:{title:'The Quran Is Light',desc:'The Quran is a light that illuminates the path through life\'s darkness. Whoever is enlightened by the Quran will never go astray.',approach:'Make the Quran your compass at every crossroad',wisdom:'The Quran is God\'s firm rope — whoever holds it is saved',action:'Reflect today on how the Quran can illuminate your decisions and life'},fr:{title:'Le Coran Est Lumière',desc:'Le Coran est une lumière qui éclaire le chemin dans les ténèbres de la vie. Celui qui est éclairé par le Coran ne s\'égarera jamais.',approach:'Faites du Coran votre boussole à chaque carrefour',wisdom:'Le Coran est la corde solide de Dieu — celui qui s\'y accroche est sauvé',action:'Réfléchissez aujourd\'hui à comment le Coran peut éclairer vos décisions et votre vie'}}
];

